import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Stack,
  Alert,
  Snackbar,
  LinearProgress,
  Chip
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  Refresh as RefreshIcon
} from '@mui/icons-material';
import { 
  getSubscriptions, 
  createSubscription, 
  updateSubscription, 
  deleteSubscription,
  refreshSubscription,
  updateSubscriptionNodes 
} from '../services/api';

const Subscriptions = () => {
  const [subscriptions, setSubscriptions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedSubscription, setSelectedSubscription] = useState(null);
  const [editSubscription, setEditSubscription] = useState({
    name: '',
    url: '',
    interval: 3600,
    enabled: true
  });

  useEffect(() => {
    fetchSubscriptions();
  }, []);

  const fetchSubscriptions = async () => {
    try {
      setLoading(true);
      const data = await getSubscriptions();
      setSubscriptions(data);
    } catch (err) {
      setError('Failed to load subscriptions');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (subscription = null) => {
    if (subscription) {
      setSelectedSubscription(subscription);
      setEditSubscription(subscription);
    } else {
      setSelectedSubscription(null);
      setEditSubscription({
        name: '',
        url: '',
        interval: 3600,
        enabled: true
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedSubscription(null);
    setEditSubscription({
      name: '',
      url: '',
      interval: 3600,
      enabled: true
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      if (selectedSubscription) {
        await updateSubscription(selectedSubscription.id, editSubscription);
      } else {
        await createSubscription(editSubscription);
      }
      await fetchSubscriptions();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError('Failed to save subscription');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteSubscription(id);
      await fetchSubscriptions();
      setSuccess(true);
    } catch (err) {
      setError('Failed to delete subscription');
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async (id) => {
    try {
      setLoading(true);
      await refreshSubscription(id);
      await fetchSubscriptions();
      setSuccess(true);
    } catch (err) {
      setError('Failed to refresh subscription');
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">Operation completed successfully</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Box sx={{ mb: 3, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h5">订阅管理</Typography>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => handleOpenDialog()}
        >
          添加订阅
        </Button>
      </Box>

      {loading && <LinearProgress sx={{ mb: 2 }} />}

      <Grid container spacing={2}>
        {subscriptions.map((subscription) => (
          <Grid item xs={12} sm={6} md={4} key={subscription.id}>
            <Card>
              <CardContent>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                  <Typography variant="h6">{subscription.name}</Typography>
                  <Stack direction="row" spacing={1}>
                    <IconButton size="small" onClick={() => handleRefresh(subscription.id)}>
                      <RefreshIcon />
                    </IconButton>
                    <IconButton size="small" onClick={() => handleOpenDialog(subscription)}>
                      <EditIcon />
                    </IconButton>
                    <IconButton size="small" onClick={() => handleDelete(subscription.id)}>
                      <DeleteIcon />
                    </IconButton>
                  </Stack>
                </Box>
                <Stack spacing={2}>
                  <Box>
                    <Typography variant="caption" color="text.secondary">更新时间</Typography>
                    <Typography variant="body2">{subscription.updateTime || 'N/A'}</Typography>
                  </Box>
                  <Box>
                    <Typography variant="caption" color="text.secondary">到期时间</Typography>
                    <Typography variant="body2">{subscription.expireTime || 'N/A'}</Typography>
                  </Box>
                  <Box>
                    <Typography variant="caption" color="text.secondary">流量信息</Typography>
                    <Typography variant="body2">
                      已用: {formatBytes(subscription.usedTraffic || 0)} / 
                      总计: {formatBytes(subscription.totalTraffic || 0)}
                    </Typography>
                  </Box>
                  <Stack direction="row" spacing={1}>
                    <Chip 
                      label={subscription.enabled ? '已启用' : '已禁用'} 
                      color={subscription.enabled ? 'success' : 'default'} 
                      size="small" 
                    />
                    {subscription.status && (
                      <Chip 
                        label={subscription.status} 
                        color={subscription.status === 'active' ? 'primary' : 'warning'} 
                        size="small" 
                      />
                    )}
                  </Stack>
                </Stack>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Dialog open={openDialog} onClose={handleCloseDialog} maxWidth="sm" fullWidth>
        <DialogTitle>
          {selectedSubscription ? '编辑订阅' : '添加订阅'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="订阅名称"
                  value={editSubscription.name}
                  onChange={(e) => setEditSubscription({ ...editSubscription, name: e.target.value })}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="订阅地址"
                  value={editSubscription.url}
                  onChange={(e) => setEditSubscription({ ...editSubscription, url: e.target.value })}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  type="number"
                  label="更新间隔(秒)"
                  value={editSubscription.interval}
                  onChange={(e) => setEditSubscription({ ...editSubscription, interval: parseInt(e.target.value) })}
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog}>取消</Button>
          <Button 
            variant="contained" 
            onClick={handleSave}
            disabled={loading}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Subscriptions;
